SELECT s.brand_name, SUM(s.product_gms) - SUM(s.shipped_cogs) - COALESCE(SUM(c.ncrc), 0) AS net_margin, SUM(s.product_gms) AS total_sales FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.brand_name IS NOT NULL GROUP BY s.brand_name ORDER BY net_margin DESC NULLS LAST LIMIT 10;